To start a new process in C++ with one file descriptor connected to its input and output, you can use the `fork()` and `dup2()` functions. Here's a basic example:

```cpp
#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
    int fd[2];
    pipe(fd);  // Create a pipe

    pid_t pid = fork();  // Fork a child process

    if (pid == -1) {
        std::cerr << "Fork failed" << std::endl;
        return 1;
    } else if (pid == 0) {  // Child process
        close(fd[1]);  // Close the write end in the child
        dup2(fd[0], STDIN_FILENO);  // Redirect stdin to the read end of the pipe
        dup2(fd[0], STDOUT_FILENO);  // Redirect stdout to the read end of the pipe
        close(fd[0]);  // Close the read end in the child

        // Execute a command (e.g., `cat`)
        execlp("cat", "cat", NULL);
        std::cerr << "Exec failed" << std::endl;
        exit(1);
    } else {  // Parent process
        close(fd[0]);  // Close the read end in the parent
        char buffer[100];
        std::cout << "Enter text: ";
        std::cin.getline(buffer, 100);
        write(fd[1], buffer, strlen(buffer));

        close(fd[1]);  // Close the write end in the parent

        wait(NULL);  // Wait for the child to finish
        std::cout << "Child process finished." << std::endl;
    }

    return 0;
}
```

This code creates a pipe, forges a new process, and redirects the child's standard input and output to the pipe. The parent process writes to the pipe, and the child reads from it and processes the data (in this case, it just echoes the input back).
